class ListNode:
    def __init__(self, x):
        self.val = x
        self.next = None

def hasCycle(head, pos=-1):
    def create_linked_list(arr, pos):
        if not arr:
            return None

        nodes = [ListNode(val) for val in arr]
        for i in range(len(nodes) - 1):
            nodes[i].next = nodes[i + 1]

        if pos >= 0:
            nodes[-1].next = nodes[pos]

        return nodes[0]

    if isinstance(head, list):
        head = create_linked_list(head, pos)

    slow = fast = head

    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
        if slow == fast:
            return True

    return False

